// components/Home.js
import React from 'react';
import ImageAndProfileLinks from './ImageAndProfileLinks';
// import WorkExperience from './WorkExperience';
import Education from './Education';
// import Hobbies from './Hobbies';
import { allPublications } from '../assets/publications/publicationData';
import PublicationItem from './PublicationItem';

const Home = () => {
  const indicesToDisplay = [0, 1, 3]; // Select publications by their index
  const nameToHighlight = 'James Rudd-Jones'; // Example name to highlight

  const featuredPublications = indicesToDisplay.map(index => {
    if (index >= 0 && index < allPublications.length) {
      return allPublications[index];
    }
    return null;
  }).filter(publication => publication !== null);

  const styles = {
    mainContent: {
      display: 'flex',
      borderBottom: '1px solid #aaa',
      paddingBottom: "20px",
    },
    leftSection: {
      flex: 0.3,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'flex-start',
      marginBottom: '-40px',
    },
    rightSection: {
      flex: 0.6,
      paddingLeft: '0px',
    },
    remainderSection: {
      flex: 0.4,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'flex-start',
      borderBottom: '1px solid #aaa',
    },
    indSection: {
      paddingTop: '20px', 
      paddingBottom: '20px',
      borderBottom: '1px solid #aaa',
    },
    lastSection: {
      paddingTop: '20px', 
    },
    selectedPublicationsSection: {
      marginTop: '0px',
      listStyleType: 'none'
    },
    aboutMe: {
      // marginBottom: '20px',
      // borderBottom: '1px solid #eee',
      // paddingBottom: '20px',
    },
    largerFont: {
      fontSize: '1.0em',
    }
    }

  return (
    <div>
      <div style={styles.mainContent}>
        <div style={styles.leftSection}>
          <ImageAndProfileLinks /> 
        </div>
        <div style={styles.rightSection}>
          <div>
            <h2>James Rudd-Jones</h2>
            <div style={styles.aboutMe}>
              {/* <h3>About Me</h3> */}
              <p style={styles.largerFont}>
                Hi, I am a third year PhD student in Machine Learning at UCL supervised 
                by <a href="https://www.mariaperezortiz.com/" target="_blank" rel="noopener noreferrer">María Pérez-Ortiz</a> and <a href="https://www.mircomusolesi.org/" target="_blank" rel="noopener noreferrer">Mirco Musolesi</a> as 
                part of the <a href="https://www.sml-group.cc/" target="_blank" rel="noopener noreferrer">Sustainability and Machine Learning Group</a>. 
                <br></br> <br></br>
                I am supported by the UCL EPSRC DTP studentship.
              </p>
            </div>
          </div>
        </div>
      </div>

      <div style={styles.remainderSection}>
        <div style={styles.indSection}>
          <h1>Research Interests</h1>
            <p style={styles.largerFont}>My main research focus covers Reinforcement Learning (RL) for chaotic dynamical systems. More 
                generally I am interested in decision making under uncertainty within physical process based scenarios (e.g. Weather/Climate/Fluids/Fusion). Enacting long horizon 
                control under chaotic dynamics is fascinating as we have to accept (and perhaps reconcile (much to the dismay of Winnicott)) a paradox: we desire to learn a behavioural 
                policy from historical data, yet due to chaotic mixing and the sensitivity to initial conditions, individual trajectories are wildly idiosyncratic and are therefore 
                virtually uninformative.
                <br></br> <br></br> 
                As an avid sailor the use of Machine Learning (ML) for the maritime industry, especially high performance sailing such as the America's Cup, is another great interest of mine.
                The heavily non-linear nature of the wind and waves makes for a very interesting applied ML domain.
                Further, pronounced by the move towards hydrofoiling boats, sailboat optimisation typically deals with heavily confounded multi-objectives such as light wind versus
                heavy wind performance or finding a balance between aerodynamic and hydrodynamic performance.
                <br></br> <br></br> 
                I also explore applications of ML for environmental and sustainable uses such as the prediction of Forest Succession, as I deeply care about the climate crisis. 
                <br></br> <br></br> 
                Please reach out for discussions and/or collaborations in any of these areas!
            </p>
        </div>

        <div style={styles.indSection}>
          {featuredPublications.length > 0 && (
            <div style={styles.selectedPublicationsSection}>
              <h1>Featured Publications</h1>
              <div style={styles.selectedPublicationsList}>
                  {featuredPublications.map((publication) => (
                    <li key={publication.id}>
                      <PublicationItem publication={publication} highlightName={nameToHighlight}/>
                    </li>
                  ))}
              </div>
            </div>
          )}
        </div>

        {/* <WorkExperience /> */}
        <Education />
        {/* <Hobbies /> */}
      </div>
    </div>
  );
};

export default Home;